var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"좋아, 이제 말끔해졌네","JPN":"よし、これでキレイになったね。","ENG":"All right. It's clean now.","TWN":"好了，這樣就乾淨多了。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"마, 말도 안 돼. 어떻게 이렇게 빨리 끝낸 거야?","JPN":"あ、ありえない。どうやってこんなに早く終わらせたの？","ENG":"W-wow. How did you finish so quickly?","TWN":"誇，誇張，你動作怎麼這麼快？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"으음, 그게 어쩐지 익숙해서 말이야.","JPN":"えっと、それがね。なぜかこういう仕事に慣れててね。","ENG":"Um, I guess I've done something similar before?","TWN":"嗯，總覺得有種熟悉的感覺。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"익숙하다고?","JPN":"慣れてる？","ENG":"Before?","TWN":"熟悉？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쩐지 전에도…… 수영복 입고 놀러갔다가 갑판 청소만 몇 시간 했던 것 같거든.","JPN":"なんとなく以前にも……\\n水着を着て遊びに行ったのに、数時間も甲板の掃除だけをやっていた気がするの。","ENG":"I remember... wearing a swimsuit on vacation and mopping the deck for hours on end.","TWN":"之前好像也有過……原本穿泳衣要去玩，結果卻打掃甲板好幾個小時的經驗。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L11_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"수영복 입고 갑판 청소? 하하, 아르바이트였던거야?","JPN":"水着で甲板掃除？　あはは。それってアルバイトか何か？","ENG":"You mopped the deck while wearing a swimsuit? Ha ha! Was it a part-time job?","TWN":"穿著泳衣打掃甲板？是打工嗎？"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"그랬……었나?","JPN":"そう……だったかな？","ENG":"I think... so?","TWN":"是……嗎？"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L13_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"미나, 의외로 사회 경험이 많구나?","JPN":"ミナはいろんな経験をしているんだね。","ENG":"You have more work experience than I thought, Mina.","TWN":"米娜，沒想到你蠻多社會經驗的嘛？"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_TOUCH"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"으음…… 그럴지도? 왠지 기억이 흐릿하네.","JPN":"ええと……そうかも？　なんだか記憶が曖昧で。","ENG":"Mm... I guess. But my memory's a bit fuzzy.","TWN":"嗯……或許吧？記憶有點模糊。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"어쨌든 미나 덕분에 문제를 하나 해결했네. 역시 미나는 대단해.","JPN":"とにかく、ミナのおかげで問題を一つ解決できたわ。\\nやっぱりミナはすごいね。","ENG":"Anyway, thanks to you, it's been solved. You're amazing, Mina.","TWN":"總之幸虧有你的幫忙，已經解決掉一個問題。米娜果然厲害！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"잠깐 기다려, 수영부 애들 불러 올게!","JPN":"ちょっと待っててね、水泳部のみんなを呼んでくる！","ENG":"Hold on. I'll go get the swim club members!","TWN":"你等我一下，我去找游泳部的人過來！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWIMMING_NPC_GEASS_NULL","text":{"KOREA":"미소녀부터 관능적인 숙녀까지, 수영부 카페에 온 것을 환영합니다~!","JPN":"美少女からアダルティーなお姉様まで、水泳部カフェへようこそ！","ENG":"From pretty young girls to sexy mature women! Welcome to the Swim Club Cafe!","TWN":"無論是清純美少女…或是性感大姊姊，歡迎光臨游泳部咖啡廳～！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWIMMING_NPC_GEASS_NULL","text":{"KOREA":"고마워, 셜리! 학생회 덕분에 카페를 열 수 있게 됐어.","JPN":"ありがとう、シャーリー！　生徒会のおかげでカフェの営業ができるわ。","ENG":"Thanks, Shirley! We can finally open our cafe, thanks to the Student Council's help.","TWN":"謝謝你，夏麗！托學生會的福，咖啡廳終於可以開張囉。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"에이, 뭘~ 힘 쓰는 건 미나가 다 했는 걸?","JPN":"ううん、力仕事はミナが全部やってくれたの。","ENG":"Don't mention it! Plus, Mina did all the hard work.","TWN":"沒有啦～都是米娜在出力的啦。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWIMMING_NPC_GEASS_NULL","text":{"KOREA":"어, 그런데 얘들아? 미안하지만 수영복 입은 김에 하나만 더 부탁할 수 있을까?","JPN":"あ、二人とも。悪いけどついでにもう一つお願いしてもいい？","ENG":"Oh, gals? Sorry, but since she's already wearing a swimsuit, can we ask for one more favor?","TWN":"不好意思，反正都已經換上泳裝，可以再麻煩你們一件事嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWIMMING_NPC_GEASS_NULL","text":{"KOREA":"내일 카페 오픈 퍼포먼스 연습에 참가해줄 수 있어? 요리 준비때문에 사람이 부족하거든.","JPN":"明日のオープン時に披露するパフォーマンスの練習に付き合ってくれない？\\n料理の準備で人手が足りないんだ。","ENG":"Could you help us practice for tomorrow's opening performance? We're short on people because of all the cooking preparations.","TWN":"你們可以一起參與明天咖啡廳開張表演的\\n彩排嗎？其他人都在準備餐點，現在人手不夠。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"뭐어? 안 돼! 오늘은 학생회 때문에 못 도와준다고 했잖아.","JPN":"ええっ？　ダメだよ！\\n今日は生徒会の仕事があるから手伝えないって言ったでしょ。","ENG":"What? No way! I told you I couldn't because of the Student Council.","TWN":"什麼？不行！我不是說今天要忙學生會的事，不能幫忙嗎？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWIMMING_NPC_GEASS_NULL","text":{"KOREA":"에이, 그러지 말고~ 셜리가 없으면 수영부 카페의 꽃이 없는 걸?","JPN":"せっかくだしお願い！　シャーリーがいないと華が無くてさ。","ENG":"C'mon, don't be shy! What's the Swim Club Cafe without you, Shirley?","TWN":"唉唷～不要這樣嘛～夏麗不在，游泳部咖啡廳就會失去色彩欸？"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWIMMING_NPC_GEASS_NULL","text":{"KOREA":"자자, 그러니까 셜리도 빨리 수영복으로 갈아입자!","JPN":"さあさあ、とりあえず水着に着替えよう！","ENG":"Now, now. Go and get changed into your swimsuit too, Shirley!","TWN":"好啦好啦，夏麗你也快點去換上泳裝吧！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"자, 잠깐! 아하핫! 간지러워!","JPN":"ちょ、ちょっと待って！　アハハ！　くすぐったいよ！","ENG":"W-wait! Aha ha ha! That tickles!","TWN":"等一下啦！哈哈哈～好癢喔！"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"흐음, 역시 셜리는 여기서도 인기가 좋구나.","JPN":"へえ、やっぱりシャーリーは水泳部でも人気者なんだ。","ENG":"Hmm, Shirley seems to be popular here too.","TWN":"嗯，夏麗果然在這裡人緣也很好呢。"},"stage":{"bg":"SUMMER_SWIMPOOL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};